solutionCode.withLogger.ts:
import type { ComponentType, FC } from 'react';

export function withLogger<P extends object>(Component: ComponentType<P>): FC<P> {
  const displayName = Component.displayName ?? Component.name ?? 'Component';

  const LoggedComponent: FC<P> = (props) => {
    console.log(`Rendering: ${displayName}`);
    return <Component {...props} />;
  };

  LoggedComponent.displayName = `withLogger(${displayName})`;
  return LoggedComponent;
}
